#include<iostream>#include<vector>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,x;        cin>>n>>x;        vector<ll>p[3];        for(int i=0;i<3;i++){            ll s=0;            p[i].push_back(s);            for(int j=0;j<n;j++){                ll a;                cin>>a;                if((s|a) !=s){                    s|=a;                    p[i].push_back(s);                }            }        }        bool ans=false;        for( ll a: p[0]){            for(ll b:p[1]){                for(ll c:p[2]){                    if((a|b|c)==x){                        ans=true;                    }                }            }        }        cout<<(ans?"Yes":"No")<<"\n";    }}